+Task<vector<ImageData>> BmpImageLoader::loadWithoutFileHeader(
+    istream& iStream,
+    const fs::path& path,
+    string_view channelSelector,
+    int priority,
+    const GainmapHeadroom& gainmapHeadroom,
+    optional<size_t> pixelDataOffset,
+    Vector2i* sizeInOut,
