+        uint32_t redX;
+        uint32_t redY;
+        uint32_t redZ;
+        uint32_t greenX;
+        uint32_t greenY;
+        uint32_t greenZ;
+        uint32_t blueX;
+        uint32_t blueY;
+        uint32_t blueZ;
