+    }
+
+    if (!getMaybeRgbFloat("GainMapMax", mGainMapMax)) {
+        throw invalid_argument{"XMP gainmap property GainMapMax is required."};
+    }
+
+    mGainMapMax = max(mGainMapMax, mGainMapMin);
+
