+template <typename T, typename U> Task<void> asyncScopeGuard(T&& cleanup, U&& body) {
+    std::exception_ptr exceptionPtr;
+    try {
+        co_await body();
+    } catch (...) { exceptionPtr = std::current_exception(); }
+
+    co_await cleanup();
+    if (exceptionPtr) {
+        std::rethrow_exception(exceptionPtr);
+    }
+}
